# Readmission prediction model results by race
# Format: {group: {TP, FP, TN, FN}}
results = {
    "Black": {"TP": 95, "FP": 78, "TN": 302, "FN": 25},
    "White": {"TP": 88, "FP": 45, "TN": 342, "FN": 25}
}

def compute_group_metrics(tp, fp, tn, fn):
    n = tp + fp + tn + fn
    predicted_positive_rate = (tp + fp) / n  # demographic parity numerator
    sensitivity = tp / (tp + fn)              # equalized odds: TPR
    fpr = fp / (fp + tn)                      # equalized odds: FPR
    return {
        "predicted_positive_rate": predicted_positive_rate,
        "sensitivity_TPR": sensitivity,
        "FPR": fpr
    }

